import { describe, expect, test } from '@a0n/gnosis/test';
import { BettyCompiler } from '../betty/compiler';
import { compileGnarly, parseGnarly } from '../gnarly-compiler';
import { PolyglotStrategyMemory } from '../polyglot-memory';
import { getPolyglotCapabilityMatrix } from '../polyglot-registry';

const GNARLY_SOURCE = `
gnarly "image-pipeline" {
  languages = ["typescript", "rust", "go"]
  entry = ingest
}

(ingest: PolyglotBridgeCall {
  language: "typescript",
  file: "ingest.ts",
  callee: "ingest"
})

(transform: PolyglotBridgeCall {
  fastest: true,
  candidates: ["rust", "go", "zig"],
  callee: "transform"
})

(emit: PolyglotBridgeCall {
  language: "go",
  file: "emit.go",
  callee: "emit"
})

(ingest)-[:PROCESS]->(transform)
(transform)-[:PROCESS]->(emit)

impl transform in rust {
  pub fn transform(input: serde_json::Value) -> serde_json::Value {
      input
  }
}
`;

describe('gnarly parser', () => {
  test('extracts metadata, embedded implementations, and GG source', () => {
    const document = parseGnarly(GNARLY_SOURCE, '/tmp/image.gnarly');

    expect(document.metadata.name).toBe('image-pipeline');
    expect(document.metadata.languages).toEqual(['typescript', 'rust', 'go']);
    expect(document.metadata.entry).toBe('ingest');
    expect(document.implementations).toHaveLength(1);
    expect(document.implementations[0]?.nodeId).toBe('transform');
    expect(document.implementations[0]?.language).toBe('rust');
    expect(document.ggSource).toContain('(transform: PolyglotBridgeCall');
    expect(document.ggSource).toContain('(ingest)-[:PROCESS]->(transform)');
    expect(document.ggSource).not.toContain('impl transform');
  });
});

describe('gnarly compiler', () => {
  test('compiles gnarly into GG, manifests, generated files, and speed hints', async () => {
    const result = await compileGnarly(GNARLY_SOURCE, {
      filePath: '/tmp/image.gnarly',
    });

    expect(result.ast?.nodes.has('transform')).toBe(true);
    expect(result.executionManifest.entry_function).toBe('ingest');
    expect(result.multiLanguageManifest?.nodeOverrides.get('emit')).toEqual({
      language: 'go',
      filePath: 'emit.go',
    });
    expect(result.generatedFiles.some((file) => file.embedded)).toBe(true);
    expect(result.speedDiagnostics).toHaveLength(1);
    expect(result.speedDiagnostics[0]?.severity).toBe('hint');
    expect(result.speedDiagnostics[0]?.code).toBe(
      'GNARLY_FASTER_LANGUAGE_AVAILABLE'
    );
    expect(result.topoRaceGg).toContain('Topo-race');
  });

  test('emits unknown-language diagnostics instead of failing parse', async () => {
    const result = await compileGnarly(
      `
(x: PolyglotBridgeCall { language: "madeup", fastest: true, candidates: ["rust"] })
`
    );

    expect(result.diagnostics.some((d) => d.code === 'GNARLY_UNKNOWN_LANGUAGE')).toBe(
      true
    );
    expect(result.ast?.nodes.has('x')).toBe(true);
  });

  test('accepts every registered language in metadata', async () => {
    const matrix = await getPolyglotCapabilityMatrix();
    const languages = matrix.languages.map((language) => language.id);
    const source = `
gnarly "registry" {
  languages = [${languages.map((language) => `"${language}"`).join(', ')}]
}

(entry: Entry)
(exit: Return)
(entry)-[:PROCESS]->(exit)
`;
    const result = await compileGnarly(source);
    expect(
      result.diagnostics.filter((d) => d.code === 'GNARLY_UNKNOWN_LANGUAGE')
    ).toEqual([]);
  });

  test('uses strategy memory as observed evidence for faster hints', async () => {
    const memory = new PolyglotStrategyMemory();
    memory.record({
      functionName: 'transform',
      language: 'go',
      filePath: '/tmp/transform.go',
      durationMs: 5,
      success: true,
      timestamp: new Date().toISOString(),
    });

    const result = await compileGnarly(GNARLY_SOURCE, {
      strategyMemory: memory,
    });
    expect(result.speedDiagnostics[0]?.evidence).toBe('observed');
    expect(result.speedDiagnostics[0]?.recommendedLanguage).toBe('go');
  });

  test('compiled GG remains valid Betty input', async () => {
    const result = await compileGnarly(GNARLY_SOURCE);
    const betty = new BettyCompiler().parse(result.ggSource);
    expect(betty.ast?.nodes.has('ingest')).toBe(true);
    expect(betty.ast?.edges).toHaveLength(2);
  });
});
